const raw = $('Webhook').first().json.body || {};
const enhanced = $input.first().json.message?.content || raw.prompt || 'a cinematic scene';
const channelId = raw.channel || raw.channel_id || 'C0AKJ788GJK';
const userId    = raw.user_id || raw.user    || '';
const clientId  = 'n8n-vid-' + Date.now();
const seed = Math.floor(Math.random() * 1_000_000_000);

// SDXL 4-frame batch → animated GIF via VHS_VideoCombine
// Generates 4 stylistic variations of the scene as an animated loop
const workflow = {
  "1": { "inputs": {"ckpt_name": "sd_xl_base_1.0.safetensors"}, "class_type": "CheckpointLoaderSimple" },
  "2": { "inputs": {"text": enhanced, "clip": ["1",1]}, "class_type": "CLIPTextEncode" },
  "3": { "inputs": {"text": "blurry, low quality, static, watermark, text, logo, deformed", "clip": ["1",1]}, "class_type": "CLIPTextEncode" },
  "4": { "inputs": {"width": 768, "height": 512, "batch_size": 4}, "class_type": "EmptyLatentImage" },
  "5": {
    "inputs": {
      "seed": seed, "steps": 20, "cfg": 7.0,
      "sampler_name": "euler_ancestral", "scheduler": "karras", "denoise": 1.0,
      "model": ["1",0], "positive": ["2",0], "negative": ["3",0], "latent_image": ["4",0]
    },
    "class_type": "KSampler"
  },
  "6": { "inputs": {"samples": ["5",0], "vae": ["1",2]}, "class_type": "VAEDecode" },
  "7": {
    "inputs": {
      "frame_rate": 3, "loop_count": 0,
      "filename_prefix": "n8n_video",
      "format": "image/gif",
      "pingpong": false, "save_output": true,
      "images": ["6",0]
    },
    "class_type": "VHS_VideoCombine"
  }
};

return [{ json: { workflow, clientId, channelId, userId, prompt: enhanced } }];

const http = require('http');

function httpGetComfyUI(path) {
  return new Promise((resolve, reject) => {
    const req = http.get({ host: 'host.docker.internal', port: 8188, path }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
        catch { resolve({}); }
      });
    });
    req.on('error', reject);
  });
}

const promptId  = $input.first().json.prompt_id;
const maxTries  = 72;

for (let i = 0; i < maxTries; i++) {
  await new Promise(r => setTimeout(r, 5000));
  const history = await httpGetComfyUI(`/history/${promptId}`);
  const entry = history[promptId];
  if (entry?.status?.completed) {
    const node = Object.values(entry.outputs || {}).find(o => o.gifs?.length || o.videos?.length || o.images?.length);
    if (node) {
      const media = node.gifs?.[0] || node.videos?.[0] || node.images?.[0];
      const buildData = $('Build ComfyUI Payload').first().json;
      return [{ json: {
        promptId,
        filename:  media.filename,
        subfolder: media.subfolder || '',
        type:      media.type || 'output',
        channelId: buildData.channelId,
        userId:    buildData.userId,
        prompt:    buildData.prompt,
        mediaType: 'gif'
      }}];
    }
  }
}
throw new Error('ComfyUI generation timed out after 6 minutes');

const https = require('https');

function postMessage(body) {
  return new Promise((resolve, reject) => {
    const data = JSON.stringify(body);
    const req = https.request({
      method: 'POST', hostname: 'slack.com', path: '/api/chat.postMessage',
      headers: {
        'Authorization': `Bearer ${$env.SLACK_BOT_TOKEN}`,
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(data)
      }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
        catch { resolve({}); }
      });
    });
    req.on('error', reject);
    req.write(data);
    req.end();
  });
}

const ctx = $input.first().json;
const channelId = ctx.channelId || 'C0AKW7W9ZPX';
const prompt = ctx.prompt || '';
const filename = encodeURIComponent(ctx.filename || '');
const subfolder = encodeURIComponent(ctx.subfolder || '');
const type = ctx.type || 'output';
const mediaType = ctx.mediaType || 'image';

// Build public URL via n8n preview webhook → ComfyUI proxy
const ngrokBase = ($env.WEBHOOK_URL || '').replace(/\/$/, '');
const imageUrl = `${ngrokBase}/webhook/preview-comfyui?filename=${filename}&subfolder=${subfolder}&type=${type}`;

const isVideo = mediaType === 'gif';
const titleText = isVideo ? ':film_frames: Video Generated' : ':art: Image Generated';
const modelNote = isVideo ? 'SDXL 4-frame GIF on RTX 5070 Ti' : 'SDXL on RTX 5070 Ti';

const blocks = [
  { type: 'header', text: { type: 'plain_text', text: titleText } },
  { type: 'section', text: { type: 'mrkdwn', text: `*Prompt:* ${prompt.slice(0, 200)}` } },
  { type: 'image', image_url: imageUrl, alt_text: 'Generated output' },
  { type: 'context', elements: [{ type: 'mrkdwn', text: `_${modelNote} · ${new Date().toLocaleTimeString()}_` }] }
];

const result = await postMessage({
  channel: channelId,
  text: `${titleText}: ${prompt.slice(0, 80)}`,
  blocks
});

if (!result.ok) {
  throw new Error(`Slack post failed: ${result.error || JSON.stringify(result)}`);
}

return [{ json: { ok: true, ts: result.ts, channel: result.channel, channelId } }];

// Restore context from Poll Until Done node (HTTP Request dropped it)
const poll = $('Poll Until Done').first().json;
const item = $input.first();
return [{
  json: {
    channelId: poll.channelId || '',
    filename: poll.filename || 'file',
    prompt: poll.prompt || '',
    uploadComment: poll.uploadComment || '{}'
  },
  binary: item.binary
}];
